import{_ as a,o as s,c as n,aw as e}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Staking Wrapper Module","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Staking Wrapper Module | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"ev-abci/modules/staking-wrapper.md","filePath":"ev-abci/modules/staking-wrapper.md","lastUpdated":1772446570000}');const l=a({name:"ev-abci/modules/staking-wrapper.md"},[["render",function(a,o,l,p,t,r){return s(),n("div",null,[...o[0]||(o[0]=[e('<h1 id="staking-wrapper-module" tabindex="-1">Staking Wrapper Module <a class="header-anchor" href="#staking-wrapper-module" aria-label="Permalink to &quot;Staking Wrapper Module&quot;">​</a></h1><p>A wrapper around the Cosmos SDK staking module that prevents validator set changes during migration.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>When migrating from CometBFT to Evolve, the validator set must be frozen to allow a clean transition to single-sequencer mode. The staking wrapper:</p><ul><li>Prevents new delegations and undelegations from affecting the validator set</li><li>Blocks validator creation and updates</li><li>Allows the migration manager to perform the final transition</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Replace your staking module import:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;">// Before</span></span>\n<span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#94EEFF;">github.com/cosmos/cosmos-sdk/x/staking</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// After</span></span>\n<span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#94EEFF;">github.com/evstack/ev-abci/modules/staking</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p>The wrapper is API-compatible with the standard staking module.</p><h2 id="behavior" tabindex="-1">Behavior <a class="header-anchor" href="#behavior" aria-label="Permalink to &quot;Behavior&quot;">​</a></h2><h3 id="normal-operation" tabindex="-1">Normal Operation <a class="header-anchor" href="#normal-operation" aria-label="Permalink to &quot;Normal Operation&quot;">​</a></h3><p>Before migration is triggered, the wrapper behaves identically to the standard staking module:</p><ul><li>Delegations work normally</li><li>Validator operations work normally</li><li>Rewards distribution works normally</li></ul><h3 id="during-migration" tabindex="-1">During Migration <a class="header-anchor" href="#during-migration" aria-label="Permalink to &quot;During Migration&quot;">​</a></h3><p>Once the migration manager signals migration mode:</p><ul><li><code>EndBlock</code> returns an empty validator update set</li><li>Delegation changes are recorded but don&#39;t affect validators</li><li>Validator creation/modification is blocked</li></ul><h3 id="after-migration" tabindex="-1">After Migration <a class="header-anchor" href="#after-migration" aria-label="Permalink to &quot;After Migration&quot;">​</a></h3><p>Post-migration, the staking module becomes read-only for validator operations. The single sequencer is now the only block producer.</p><h2 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to &quot;Integration&quot;">​</a></h2><h3 id="app-go" tabindex="-1">app.go <a class="header-anchor" href="#app-go" aria-label="Permalink to &quot;app.go&quot;">​</a></h3><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#767676;"> (</span></span>\n<span class="line"><span style="color:#DBD7CA;">    stakingkeeper </span><span style="color:#BFF3C280;">&quot;</span><span style="color:#94EEFF;">github.com/evstack/ev-abci/modules/staking/keeper</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#DBD7CA;">    stakingtypes </span><span style="color:#BFF3C280;">&quot;</span><span style="color:#94EEFF;">github.com/cosmos/cosmos-sdk/x/staking/types</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#767676;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// In your NewApp function:</span></span>\n<span class="line"><span style="color:#DBD7CA;">app</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">StakingKeeper </span><span style="color:#767676;">=</span><span style="color:#DBD7CA;"> stakingkeeper</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">NewKeeper</span><span style="color:#767676;">(</span></span>\n<span class="line"><span style="color:#DBD7CA;">    appCodec</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#DBD7CA;">    keys</span><span style="color:#767676;">[</span><span style="color:#DBD7CA;">stakingtypes</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">StoreKey</span><span style="color:#767676;">],</span></span>\n<span class="line"><span style="color:#DBD7CA;">    app</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">AccountKeeper</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#DBD7CA;">    app</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">BankKeeper</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#DBD7CA;">    authtypes</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">NewModuleAddress</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">govtypes</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">ModuleName</span><span style="color:#767676;">).</span><span style="color:#94EEFF;">String</span><span style="color:#767676;">(),</span></span>\n<span class="line"><span style="color:#767676;">)</span></span></code></pre></div><h3 id="module-manager" tabindex="-1">Module Manager <a class="header-anchor" href="#module-manager" aria-label="Permalink to &quot;Module Manager&quot;">​</a></h3><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#767676;"> (</span></span>\n<span class="line"><span style="color:#DBD7CA;">    staking </span><span style="color:#BFF3C280;">&quot;</span><span style="color:#94EEFF;">github.com/evstack/ev-abci/modules/staking</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#767676;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// In your module manager:</span></span>\n<span class="line"><span style="color:#DBD7CA;">app</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">ModuleManager </span><span style="color:#767676;">=</span><span style="color:#DBD7CA;"> module</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">NewManager</span><span style="color:#767676;">(</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // ... other modules</span></span>\n<span class="line"><span style="color:#DBD7CA;">    staking</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">NewAppModule</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">appCodec</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> app</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">StakingKeeper</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> app</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">AccountKeeper</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> app</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">BankKeeper</span><span style="color:#767676;">),</span></span>\n<span class="line"><span style="color:#767676;">)</span></span></code></pre></div><h2 id="queries" tabindex="-1">Queries <a class="header-anchor" href="#queries" aria-label="Permalink to &quot;Queries&quot;">​</a></h2><p>All standard staking queries remain available:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">appd</span><span style="color:#BFF3C2;"> query</span><span style="color:#BFF3C2;"> staking</span><span style="color:#BFF3C2;"> validators</span></span>\n<span class="line"><span style="color:#94EEFF;">appd</span><span style="color:#BFF3C2;"> query</span><span style="color:#BFF3C2;"> staking</span><span style="color:#BFF3C2;"> delegations</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">addres</span><span style="color:#DBD7CA;">s</span><span style="color:#888888;">&gt;</span></span>\n<span class="line"><span style="color:#94EEFF;">appd</span><span style="color:#BFF3C2;"> query</span><span style="color:#BFF3C2;"> staking</span><span style="color:#BFF3C2;"> pool</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/ev-abci/modules/migration-manager">Migration Manager</a> — Coordinate the migration</li><li><a href="/ev-abci/migration-from-cometbft">Migration from CometBFT</a> — Full migration guide</li></ul>',28)])])}]]);export{o as __pageData,l as default};
